/bin/zsh -lc "uv run python - <<'PY'
import inspect
from eden_storage.protocol import Store
from eden_wire.client import StoreClient

store_methods = {}
for name, obj in Store.__dict__.items():
    if name.startswith('_'):
        continue
    if isinstance(obj, property):
        store_methods[name] = ('property', None)
    elif callable(obj):
        store_methods[name] = ('callable', inspect.signature(obj))

missing = []
mismatch = []
for name, (kind, sig) in store_methods.items():
    if not hasattr(StoreClient, name):
        missing.append(name)
        continue
    attr = getattr(StoreClient, name)
    if kind == 'property':
        if not isinstance(StoreClient.__dict__.get(name), property):
            mismatch.append((name, 'expected property'))
    else:
        client_sig = inspect.signature(attr)
        if client_sig "'!= sig:
            mismatch.append((name, str(sig), str(client_sig)))

print('"'MISSING', missing)
print('MISMATCH')
for item in mismatch:
    print(item)
PY"

